import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence, useInView } from "framer-motion";

const IMG = {
  carousel_noisette: "data:image/jpeg;base64,",
  carousel_truffe: "data:image/jpeg;base64,",
  carousel_cacao: "data:image/jpeg;base64,",
  tasting_attaque: "data:image/jpeg;base64,",
  tasting_coeur: "data:image/jpeg;base64,",
  tasting_chute: "data:image/jpeg;base64,",
  tasting_silence: "data:image/jpeg;base64,",
  splash_hero: "data:image/jpeg;base64,",
  fs_hotel: "data:image/jpeg;base64,",
  ritual_sip_circle: "data:image/png;base64,",
  ritual_tear_circle: "data:image/png;base64,",
  larme_origin: "data:image/jpeg;base64,",
  larme_blanche: "data:image/jpeg;base64,",
  larme_noor: "data:image/jpeg;base64,",
  larme_ete: "data:image/jpeg;base64,",
  larme_noire: "data:image/jpeg;base64,",
  fs_logo: "data:image/png;base64,",
  logo_cd: "data:image/png;base64,",
  outlet_butcher: "data:image/jpeg;base64,",
  outlet_milano: "data:image/jpeg;base64,",
  outlet_crust: "data:image/jpeg;base64,",
  outlet_saikindo: "data:image/jpeg;base64,",
  outlet_meylas: "data:image/jpeg;base64,",
  outlet_hideaway: "data:image/jpeg;base64,",
  ingredient_blacklime: "data:image/jpeg;base64,",
};

export default function ColetteDemayFourSeasons() {
  const [phase, setPhase] = useState("splash");
  const [lang, setLang] = useState("EN");
  const [carouselIngredientIndex, setCarouselIngredientIndex] = useState(0);
  const [tastingStep, setTastingStep] = useState(0);
  const [tastingProgress, setTastingProgress] = useState(0);
  const [larmeIndex, setLarmeIndex] = useState(0);
  const [conciergeStep, setConciergeStep] = useState("choice"); // choice | form | thanks
  const [conciergeChoice, setConciergeChoice] = useState(null); // suite | gift

  // Ingredients carousel auto-advance (4 slides × 6s)
  useEffect(() => {
    if (phase !== "ingredients") return;
    const id = setInterval(() => {
      setCarouselIngredientIndex((i) => {
        if (i >= 3) {
          clearInterval(id);
          setTimeout(() => setPhase("tasting"), 1500);
          return i;
        }
        return i + 1;
      });
    }, 6000);
    return () => clearInterval(id);
  }, [phase]);

  // Tasting steps auto-advance with progress tracking (4 steps × 8.5s)
  useEffect(() => {
    if (phase !== "tasting") return;
    if (tastingStep === 0) { setTastingStep(1); setTastingProgress(0); return; }

    const DURATION = 8500;
    const TICK = 50;
    let elapsed = 0;
    setTastingProgress(0);

    const progressId = setInterval(() => {
      elapsed += TICK;
      setTastingProgress(Math.min(elapsed / DURATION, 1));
    }, TICK);

    const stepId = setTimeout(() => {
      clearInterval(progressId);
      if (tastingStep >= 4) {
        setTimeout(() => setPhase("larmes_intro"), 1800);
      } else {
        setTastingStep(tastingStep + 1);
      }
    }, DURATION);

    return () => { clearInterval(progressId); clearTimeout(stepId); };
  }, [phase, tastingStep]);

  // Larmes carousel auto-advance (5 slides × 9s each, so each slide is fully visible ~7s after transitions)
  useEffect(() => {
    if (phase !== "larmes") return;
    const id = setInterval(() => {
      setLarmeIndex((i) => {
        if (i >= 4) {
          clearInterval(id);
          setTimeout(() => setPhase("concierge"), 2000);
          return i;
        }
        return i + 1;
      });
    }, 6000);
    return () => clearInterval(id);
  }, [phase]);

  const handleSelectLang = (l) => {
    setLang(l);
    setPhase("hotel");
  };

  const resetAll = () => {
    setPhase("splash");
    setCarouselIngredientIndex(0);
    setTastingStep(0);
    setLarmeIndex(0);
    setConciergeStep("choice");
    setConciergeChoice(null);
  };

  return (
    <>
      <FontStyles />
      <AmbientAudio lang={lang} shouldAutoPlay={phase !== "splash"} />
      {phase !== "scroll" ? (
        <div className="fixed inset-0 overflow-hidden" style={{ backgroundColor: "#050304" }}>
          <AnimatePresence mode="wait">
            {phase === "splash" && <SplashScreen key="splash" lang={lang} onSelectLang={handleSelectLang} />}
            {phase === "hotel" && <HotelScreen key="hotel" lang={lang} onContinue={() => setPhase("invitation")} />}
            {phase === "invitation" && <InvitationScreen key="inv" lang={lang} onComplete={() => setPhase("ritual")} />}
            {phase === "ritual" && <RitualScreen key="ritual" lang={lang} onComplete={() => setPhase("ingredients_intro")} />}
            {phase === "ingredients_intro" && <IngredientsIntroScreen key="ii" lang={lang} onComplete={() => { setPhase("ingredients"); setCarouselIngredientIndex(0); }} />}
            {phase === "ingredients" && <IngredientsCarousel key="ing" lang={lang} index={carouselIngredientIndex} />}
            {phase === "tasting" && <TastingScreen key="tast" lang={lang} step={tastingStep} progress={tastingProgress} />}
            {phase === "larmes_intro" && <LarmesIntroScreen key="li" lang={lang} onComplete={() => { setPhase("larmes"); setLarmeIndex(0); }} />}
            {phase === "larmes" && <LarmesCarousel key="lar" lang={lang} index={larmeIndex} />}
            {phase === "concierge" && (
              <ConciergeScreen key="con" lang={lang}
                step={conciergeStep} choice={conciergeChoice}
                onChoose={(c) => { setConciergeChoice(c); setConciergeStep("form"); }}
                onSubmit={() => setConciergeStep("thanks")}
                onExplore={() => setPhase("scroll")}
                onRestart={resetAll} />
            )}
          </AnimatePresence>
        </div>
      ) : (
        <ScrollExperience lang={lang} onRestart={resetAll} />
      )}
    </>
  );
}

function FontStyles() {
  return (
    <style>{`
      @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;1,400;1,500&family=Inter:wght@300;400;500;600&family=Pinyon+Script&family=Amiri:ital@0;1&family=Reem+Kufi:wght@400;500;600&display=swap');
      .font-display { font-family: 'Cormorant Garamond', serif; }
      .font-body { font-family: 'Inter', sans-serif; }
      .font-handwritten { font-family: 'Pinyon Script', cursive; }
      .font-arabic { font-family: 'Amiri', serif; }
      .font-arabic-display { font-family: 'Reem Kufi', sans-serif; }
      .tracking-couture { letter-spacing: 0.25em; }
      .tracking-luxe { letter-spacing: 0.3em; }
      .paper-texture {
        background-image:
          radial-gradient(circle at 20% 30%, rgba(255,255,255,0.015) 0%, transparent 50%),
          radial-gradient(circle at 80% 70%, rgba(184,150,90,0.025) 0%, transparent 50%);
        mix-blend-mode: overlay;
      }
      html, body, #root { background-color: #050304; }
      body { -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; }
      input, textarea { font-family: inherit; }
      input:focus, textarea:focus { outline: none; }
    `}</style>
  );
}

/* ───── AMBIENT AUDIO — bulletproof HTML audio ───── */
function AmbientAudio({ lang, shouldAutoPlay }) {
  const [playing, setPlaying] = useState(false);
  const [mounted, setMounted] = useState(false);
  const audioRef = useRef(null);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (!mounted || !shouldAutoPlay || !audioRef.current) return;
    try {
      audioRef.current.volume = 0.5;
      audioRef.current.play().then(() => setPlaying(true)).catch(() => {});
    } catch (e) {}
  }, [mounted, shouldAutoPlay]);

  const toggle = () => {
    try {
      if (!audioRef.current) return;
      if (playing) {
        audioRef.current.pause();
        setPlaying(false);
      } else {
        audioRef.current.play().then(() => setPlaying(true)).catch(() => {});
      }
    } catch (e) {}
  };

  if (!mounted) return null;

  return (
    <>
      <audio ref={audioRef} src="/debussy.mp3" loop preload="auto" />
      {shouldAutoPlay && (
        <button
          onClick={toggle}
          className="fixed z-50 top-4 right-4 transition-all flex items-center gap-2"
          style={{
            backgroundColor: playing ? "rgba(184,150,90,0.18)" : "rgba(5,3,4,0.55)",
            backdropFilter: "blur(12px)",
            WebkitBackdropFilter: "blur(12px)",
            border: "1px solid rgba(184,150,90,0.35)",
            padding: "8px 14px",
            borderRadius: "2px",
          }}
        >
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#b8965a" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
            {playing ? (
              <>
                <path d="M11 5 6 9H2v6h4l5 4V5z" />
                <path d="M15.54 8.46a5 5 0 0 1 0 7.07" />
                <path d="M19.07 4.93a10 10 0 0 1 0 14.14" />
              </>
            ) : (
              <>
                <path d="M11 5 6 9H2v6h4l5 4V5z" />
                <line x1="23" y1="9" x2="17" y2="15" />
                <line x1="17" y1="9" x2="23" y2="15" />
              </>
            )}
          </svg>
          <span className={`text-[9px] tracking-luxe font-body uppercase ${lang === "AR" ? "font-arabic" : ""}`}
            style={{ color: "#b8965a" }}>
            {lang === "AR" ? (playing ? "صمت" : "ديبوسي") : (playing ? "Silence" : "Debussy")}
          </span>
        </button>
      )}
    </>
  );
}

