    EN: { eyebrow: "Colette", title: "The digital sommelier.", intro: "Four questions, composed for you. Answer what feels true — she will whisper the right Larme.", reset: "Ask again" },
    AR: { eyebrow: "كوليت", title: "الساقي الرقمي.", intro: "أربعة أسئلة، مؤلفة لك. أجب بما تشعر به صادقاً — ستهمس بالقطرة المناسبة.", reset: "اسأل مرة أخرى" },
